css:
/* 朝雾 v1.0 (改色版: 暖棕薄荷)
   配色：#ffffff #eedcdd #c3dcdf #7bbcc0 #ae9b88 #7d5434
*/

/* 添加您的自定义字体 */
@font-face {
  font-family: 'YourCustomFont';  /* 给字体起个名字 */
  src: url('https://files.catbox.moe/ghaff9.ttf') format('truetype');
  font-display: swap;
}
body, button, input, textarea {
  font-family: "YourCustomFont", "Microsoft YaHei", sans-serif !important;
  color: #7d5434 !important; /* 强制应用深咖主色 */
}
p {
  font-family: "YourCustomFont";
  font-size: 15.3px;
  text-align: justify;
  text-justify: inter-word;
}

/* ===== 核心变量重新定义 ===== */
:root {
  /* 定义新色板 */
  --color-bg-paper: #ffffff;   /* 纸张白 */
  --color-light:    #eedcdd;   /* 浅粉藕 (用于混合/高光) */
  --color-sub:      rgba(196, 225, 228, 1);   /* 浅薄荷 (用于阴影/辅助) */
  --color-main:     rgba(100, 162, 166, 1);   /* 青碧色 (主边框/图标) */
  --color-mid:      rgba(152, 198, 198, 1);   /* 暖卡其 (次要文字) */
  --color-dark:     rgba(95, 62, 36, 1);   /* 深咖色 (主要文字) */

  /* 覆盖 SmartTheme 变量 */
  --SmartThemeBodyColor: var(--color-dark) !important;
  --SmartThemeBorderColor: var(--color-main) !important;
  --SmartThemeBlurTintColor: var(--color-light) !important;
  --SmartThemeEmColor: var(--color-mid) !important;
  --SmartThemeQuoteColor: var(--color-main) !important;
  --SmartThemeUnderlineColor: var(--color-mid) !important;

  /* 重新计算混合色 */
  --混合: color-mix(in srgb, var(--SmartThemeBorderColor) 40%, var(--color-bg-paper));
  --下划线: color-mix(in srgb, var(--SmartThemeUnderlineColor) 20%, var(--color-bg-paper));
}

/* ===== 文本样式 ===== */
/* 对话 */
q {
  position: relative;
  background-image: 
    linear-gradient(to top,
    var(--color-bg-paper) 0%, transparent 5px, transparent calc(100% - 5px), var(--color-bg-paper) 100%),
    linear-gradient(to right,
    transparent 0%, var(--下划线) 20px, var(--下划线) calc(100% - 20px), transparent 100%);
  border-radius: 1px;
  box-shadow: 1px 1px 1px rgba(52, 125, 112, 0.08); /* 阴影改为深咖色系 */
}

/* 斜体 */
em {
  color: var(--color-mid) !important; 
  text-shadow: 
    0 0 1px var(--SmartThemeEmColor), 
    0 0 1px var(--SmartThemeEmColor);
}

/* 删除 */
del {
  color: var(--SmartThemeUnderlineColor);
  text-decoration-color: var(--color-main);
}

/* 代码块 */
code {
  color: var(--color-bg-paper) !important;
  background: var(--SmartThemeBorderColor) !important;
  border: none;
  box-shadow: 1px 1px 1px var(--SmartThemeBorderColor) !important;
}

.mes pre code {
  position: relative;
  border-radius: 3px;
  border: none;
  box-shadow:
    inset 0 0 13px rgba(174, 155, 136, 0.15), /* 卡其色阴影 */
    1px 1px 2px rgba(125, 84, 52, 0.2) !important; /* 深咖色阴影 */
  background-color: var(--color-bg-paper)  !important;
  background-image: url("https://files.catbox.moe/7bgdl4.png")  !important;
  background-size: 100% auto;
  background-repeat: repeat;
  color: var(--color-dark) !important;
}

/* md引用文本 */
blockquote {
  background: linear-gradient(to right, var(--color-bg-paper), var(--下划线), transparent) !important;
  border-color: var(--SmartThemeEmColor) !important;
  color: var(--color-dark) !important;
}


/* 代码块内文字 */
.hljs {
  color: var(--SmartThemeBodyColor) !important;
  font-size: var(--mainFontSize) !important;
  line-height: 1.6;
}


hr {
  background: color-mix(in srgb, var(--SmartThemeBorderColor) 75%, transparent);
}

/* 选中文字高亮 */
::selection {
  background: color-mix(in srgb, var(--SmartThemeQuoteColor) 30%, var(--color-bg-paper));
  color: var(--SmartThemeBodyColor);
}

/* 全局头像 */
.avatar img,
body.big-avatar .avatar img{
  box-shadow: none;
  border: none;
}
.avatar:not(.mes .avatar):not(
#HotSwapWrapper .avatar) {
  position: relative;
  &::before {
    content: "";
    position: absolute;
    aspect-ratio: 1 / 1;
    width: 140%;
    top: 47%;
    left: 50%;
    transform: translate(-50%, -50%);
    background: url("https://files.catbox.moe/6yta6e.png");
    background-size: 100%;
    filter: hue-rotate(-20deg) sepia(0.3); /* 调整光环为暖色调 */
  }
}

/* ===== 滚动条 ===== */
::-webkit-scrollbar {
  width: 4px;
}

::-webkit-scrollbar-thumb {
  background:
    linear-gradient(135deg, var(--SmartThemeBorderColor) 0%, var(--SmartThemeBlurTintColor) 100%);
  border: 0.2px solid var(--SmartThemeBorderColor) !important;
  box-shadow: none !important;
}

#chat::-webkit-scrollbar {
    display: none;
}

/* ----- 滑动条 ----- */
input[type="range"] {
  background: 
    linear-gradient(185deg, var(--SmartThemeBorderColor) 0%, var(--SmartThemeBlurTintColor) 100%) !important;
  border-radius: 15px !important;
  height: 5px !important;
  filter: none !important;
  box-shadow: 
    1px 1px 1px var(--混合),
    -1px -1px 1px rgba(174, 155, 136, 0.2) !important;
}

input[type="range"]::-webkit-slider-thumb {
  filter: none !important;
  background: 
    linear-gradient(135deg, var(--SmartThemeBorderColor) 0%, var(--SmartThemeBlurTintColor) 100%);
  border-radius: 50%;
  border: none;
  box-shadow: 
    1px 1px 1px rgba(125, 84, 52, 0.2),
    -1px -1px 1px rgba(174, 155, 136, 0.2);
}

/* ===== 顶栏 ===== */
#top-bar,
body.no-blur #top-bar {
  box-shadow: none !important;
  outline: 1px solid var(--SmartThemeBlurTintColor) !important;
  background-color: var(--color-bg-paper) !important;
}

.drawer-icon.fa-fw {
  display: flex;
  overflow: visible;
  justify-content: center;
  font-size: calc(var(--mainFontSize) * 1.15);
  color: var(--color-main) !important;
}

/* 顶栏图标 */
#leftNavDrawerIcon::before { 
  content: "\f0ae";
}

/* 插头 */
#API-status-top:not(.redOverlayGlow)::before {
  content: "\f0c6";
}

/* 未连接状态 */
#API-status-top.redOverlayGlow::before {
  content: "\f714" !important;
  color: #FF787D !important;
}

#advanced-formatting-button .drawer-icon::before {
  content: "\f1dc";
}

#WI-SP-button .drawer-icon::before {
  content: "\f02a";
}

#user-settings-button .drawer-icon::before {
    content: "\f49e";
}

#backgrounds-drawer-toggle .drawer-icon::before {
  content: "\f302";
}

#extensions-settings-button .drawer-icon::before {
  content: "\f1ea";
}

#persona-management-button .drawer-icon::before {
  content: "\f21e";
}

#rightNavDrawerIcon::before {
  content: "\f2b9";
}

/* 顶栏(补记忆表格) */
#table_drawer_icon.drawer-icon::before {
    content: "\f080";
}

.drawer-icon.fa-fw:hover {
  filter: drop-shadow(0 0 3px rgba(123, 188, 192, 0.5));
  transform: scale(1.05);
  transition: filter 0.3s ease, transform 0.3s ease;
}

/* top-bar插件 */
#extensionTopBar {
  border: none !important;
  border-bottom: 1px solid var(--混合) !important;
  border-radius: 0 0 5px 5px !important;
  background-color: var(--color-bg-paper) !important;
}

/* ===== 输入框 ===== */
/* 底栏宽度 */
#send_form {
  width: 92%;
}

#send_form, 
body.no-blur #send_form {
  border-radius: 8px;
  padding: 3px;
  border: 1.2px solid var(--SmartThemeBorderColor) !important;
  outline: 2px solid var(--SmartThemeBlurTintColor) !important;
  background-color: var(--color-bg-paper) !important;
  box-shadow:
    inset 0 0 20px rgba(255, 255, 255, 0.5),
    0 0 10px rgba(195, 220, 223, 0.5),
    0 0 7px rgba(195, 220, 223, 0.4);
}

#send_textarea {
  clip-path: none !important;
  box-shadow: none !important;
  border: none;
  color: var(--color-dark) !important;
}

#send_form textarea:focus {
  box-shadow: 
    1px 1px 2.5px var(--混合),
    inset 0 0 15px var(--SmartThemeBlurTintColor);
  background-color: color-mix(in srgb, var(--SmartThemeBorderColor) 15%, var(--color-bg-paper));
}

/* 底栏图标 */
#quick-reply-rocket-button,
#send_form .fa-solid {
  font-size: calc(var(--mainFontSize) * 1.25);
  color: var(--SmartThemeBorderColor);
}

#options_button::before {
    content: "\f10d";
}

#extensionsMenuButton::before {
    content: "\f891";
}

#send_but::before {
    content: "\f10e";
}

#mes_stop i::before {
    content: "\f05e";
    color: #FF787D;
}

/* 输入框文案自定义 */
#send_textarea::placeholder {
    opacity: 0;
}

#nonQRFormItems {
    position: relative;
    display: flex;
    align-items: center;
}

/* 📍输入框文案 */
#nonQRFormItems::before {
    content: "₊⁺₊⊹𝑴𝒊𝒔𝒕𝒊𝒔𝒍𝒆'𝒔𝑬𝒄𝒉𝒐 𓏸˚𓈒⁺₊⁺";
    position: absolute;
    left: calc(50% + 20px); /* 左右位置 */
    top: 50%;
    transform: translate(-50%, -50%);
    font-size: calc(var(--mainFontSize) * 0.9);
    color: var(--SmartThemeBorderColor);
    pointer-events: none;
    z-index: 1;
}

#nonQRFormItems:has(#send_textarea:focus)::before,
#nonQRFormItems:has(#send_textarea:not(:placeholder-shown))::before {
    display: none !important;
}

/* 底栏悬浮 by NAKARI */
#form_sheld {
  position: absolute;
  bottom: 10px;  /* 底栏与输入框距离 */
}

#chat {
  max-height: calc(100dvh + var(--bottomFormBlockSize));
  height: calc(100dvh + var(--bottomFormBlockSize));
}

/* 消除导航栏+底栏的缝隙，同时让底栏紧贴界面底部 by zzzskari */
#form_sheld {
  margin: 0 auto !important;
}

#sheld {
  top: var(--bottomFormBlockSize);
  height: calc(100dvh - var(--bottomFormBlockSize));
  max-height: calc(100dvh - var(--bottomFormBlockSize));
}

/* 当 textarea 聚焦或有内容时 */
#form_sheld:has(#send_textarea:focus),
#form_sheld:has(#send_textarea:not(:placeholder-shown)) {
  position: sticky;
}

.list-group,
.options-content,
#options {
  box-shadow: none !important;
}

/* quickPersona */
#quickPersonaImg {
    box-shadow: none !important;
}

.list-group-item .quickPersonaMenuImg {
    box-shadow: none;
    border: none;
}

#qr--bar > .qr--buttons .qr--button {
  border: none !important;
  border-radius: 2px !important;
  background: transparent;
  box-shadow:
    1px 1px 2px var(--SmartThemeBorderColor),
    0 0 2px var(--SmartThemeBorderColor) !important;
}

/* ===== 消息区域 ===== */
#chat {
  border: none;
}

/* --- 欢迎页 --- */
.welcomePanel {
  background: none !important;
  border: none !important;
}

.welcomePanel .recentChatList .recentChat {
    margin-bottom: 10px;
    border-radius: 5px;
    background-color: var(--SmartThemeBlurTintColor);
    outline: 1.5px solid var(--SmartThemeBlurTintColor) !important;
    box-shadow:
      0 0 3px rgba(255, 255, 255, 0.85),
      0 0 7px rgba(255, 255, 255, 0.85);
}

.chatNameContainer {
    padding: 1px 3.5px;
}

.mes_button.showRecentChats .fa-circle-chevron-down::before {
  content: "\f0e0";
}

.mes_button.hideRecentChats .fa-circle-xmark::before {
  content: "\f658";
}

.mes_button.hideRecentChats,
.mes_button.showRecentChats {
  opacity: 0.55;
  visibility: visible;
}

/* --- 思维链 --- */
.mes_reasoning_header {
  background-color: transparent;
  margin: 0 auto;
}

.mes_reasoning_arrow {
  display: none;
}

/* 📍思维链文字自定义 */
.mes_reasoning_header_title {
  font-size: 0;
  &::before {
    content: "• 𝒂𝒏𝒐𝒏𝒚𝒎𝒐𝒖𝒔 𝒍𝒆𝒕𝒕𝒆𝒓 •";
    font-size: calc(var(--mainFontSize) * 0.9);
    color: var(--SmartThemeEmColor);
    border-radius: 5px;
    padding: 2px 6px;
    box-shadow:
      0 0 2.5px var(--混合),
      1px 1px 2.5px var(--混合),
      inset 0 0 12px var(--color-bg-paper);
  }
}

@media (max-width: 768px) {
  .mes_reasoning_details {
    position: relative;
}

  .mes_reasoning_details[open] {
  width: 100%;
}

  .mes_reasoning {
    width: 100%;
    max-height: 500px; /* 内容高度 */
    overflow: hidden auto;
    font-size: calc(var(--mainFontSize) * 0.9);
    border-radius: 8px;
    border: 1px dotted var(--SmartThemeBorderColor);
    background: color-mix(in srgb, var(--SmartThemeUnderlineColor) 15%, var(--color-bg-paper));
  }

  .mes_reasoning_actions {
     position: absolute;
     right: 5px;
     top: 5px;
     z-index: 10;
     flex-shrink: 0;
     padding: 0 5px;
  }
}

/* --- 最新消息 --- */
.last_mes {
  margin-bottom: 70px !important;
}

.last_mes .mesAvatarWrapper {
  padding-bottom: 0px;
}

.last_mes[is_user="false"] .mes_block {
  margin-bottom: 30px !important;
}

/* --- 消息框 ---*/
.mes {
  flex-direction: column;
  position: relative;
  width: calc(100% - 15px);
  margin: 15px auto;
  padding: 12px 7px 17px;
  border-radius: 5px;
  box-shadow: 0 0 1px rgba(125, 84, 52, 0.1);
  background-color: var(--color-bg-paper);
  box-shadow:
    0 0 2px rgba(195, 220, 223, 0.85),
    0 0 5px rgba(123, 188, 192, 0.85),
    inset 0 0 45px rgba(255, 255, 255, 0.5);
}

/* --- 文本区域 --- */
.mes_block {
  display: flex;
  flex-direction: column;
  overflow: visible;
  transform: none !important;
  padding: 5px 0 0;
  border-top: 1px dashed var(--SmartThemeBorderColor);
  border-bottom: 1px solid var(--SmartThemeBorderColor);
  background: url("https://files.catbox.moe/xswf7x.png");
  background-size: 100% auto;
  background-repeat: repeat-y;
  background-color: var(--color-bg-paper); /* 确保背景色正确 */
}

/* --- 文本框 --- */
.mes_text {
  padding: 0 2px;
  text-align: justify;
}

.mes[is_user="true"] .mes_text {
  padding: 5px 0;
}

.mes[is_user="true"] p:last-child {
  margin-bottom: 0;
}

.mes_text p:empty {
    display: none;
}

/* 首行缩进 */
.mes_text p {
  text-indent: 2em;
}

/* --- 小铅笔 --- */
.mes_button,
.mes_edit_buttons {
  font-size: calc(var(--mainFontSize) * 1.01);
  filter: none !important;
  color: var(--SmartThemeBorderColor);
}

.mes .menu_button {
  opacity: 1;
  color: var(--color-mid);
  transform: scale(0.85);
  border-radius: 8px;
  border: none;
  box-shadow:
    0 0 5px rgba(125, 84, 52, 0.15),
    1px 1px 3px var(--混合),
    inset 0 0 20px var(--SmartThemeBlurTintColor);
  background-color: var(--color-bg-paper);
}

.mes .fa-star::before {
  content: "\f02b" !important; 
}

#chat .fa-solid.fa-star {
   color: #FF787D !important;
}

.fa-star::before {
    content: "\f004" !important; 
}

.fa-solid.fa-star {
   color: #FF787D !important;
}

.mes_edit::before {
    content: "\f00c";
}

.extraMesButtonsHint::before {
    content: "\f00d" !important;
}

/* --- 左右箭头 --- */
.swipe_right,
.swipe_left {
  opacity: 0.75;
  color: var(--SmartThemeBorderColor);
  font-size: 1.2em;
}

.swipe_right::before {
  content: "\f101";
}

.swipe_left::before {
  content: "\f100";
 }

/* by KAKAA */
.swipeRightBlock {
  flex-direction: row-reverse;
  bottom: calc(var(--swipeCounterHeight) + var(--swipeCounterMargin));
  margin-right: 15px;
}

.swipes-counter {
  transform: translate(25%, 20%);
}

/* ---名字区域 --- */
.mes .ch_name {
  order: 1;
  border-bottom: 1px solid var(--SmartThemeBorderColor);
  margin-bottom: 2px;
  align-items: center;
  color: var(--color-dark) !important;
}

/* 📌文字装饰(可自定义) */
/* 1. 常规状态下的定位 */
.mes .ch_name::before {
    /* 确保显示 */
    display: block !important;
    content: "× × 择 日 再 见 面 × ×"; /* 这里的文字可以自己改 */

    /* 绝对定位 */
    position: absolute !important;

    /* 水平居中 */
    left: 50% !important;
    transform: translateX(-50%) !important;

    /* 🟢 垂直定位核心：放在底部时间戳的上面 */
    top: auto !important; 
    bottom: 28px !important; /* 时间戳大约占20px高度+12px底边距，所以这里设38px刚好在上面 */

    /* 样式微调 */
    font-size: calc(var(--mainFontSize) * 0.75) !important;
    color: var(--color-mid) !important;
    font-weight: bold !important;
    pointer-events: none; /* 防止挡住点击 */
    z-index: 15;
    white-space: nowrap;
    opacity: 0.6; /* 稍微淡一点，不抢眼 */
}

/* 2. 特殊情况：最新一条消息 (Last Message) */
/* 因为最新消息的时间戳位置会往上跑(为了避开头像)，所以装饰也要跟着往上跑 */
.last_mes[is_user="false"] .ch_name::before {
    bottom: 58px !important; /* 原本是38px，加高30px以配合时间戳的上移 */
}
/* --- 📌名字(可自定义) --- */
.mes .name_text {
  position: absolute;
  top: 60px;
  left: 45px;
  writing-mode: vertical-rl;
  &::before {
    content: "文/";
  }
  &::after {
    content: "《未来是只海鸥》";
    font-size: 1.3em;
    position: absolute;
    white-space: nowrap;
    top: -60px;
    right: 100%;
    margin-right: 5px;
  }
}
/* 手机端修改字体大小 */
@media (max-width: 768px) {
  .mes .name_text {
    font-size: 14px;
  }
}

/* --- 📌时间戳(位置调整) --- */
.mes .timestamp {
  position: absolute;
  top: calc(100% - 25px);
  left: 50%;
  transform: translateX(-50%);
  padding: 1px 5px;
  background: var(--color-bg-paper);
  color: var(--color-mid) !important;
  opacity: 1;
}

.last_mes[is_user="false"] .timestamp {
  top: calc(100% - 55px);
}

/* --- 📌头像区域(图床链接更换) --- */
.mesAvatarWrapper {
  display: flex;
  align-self: flex-start;
  align-items: flex-end;
  justify-content: flex-end;
  width: 100%;
  height: 170px; /* 整体高度调整① */
  flex: 0 0 auto;
  gap: 5px;
  margin-bottom: 2px;
  padding-bottom: 5px !important;
  border-bottom: 1.2px solid var(--SmartThemeBorderColor);
  &::before {
    content: "";
    position: absolute;
    top: 8px;
    right: 8px;
    width: 77%;
    height: 125px;/* 高度调整② */
    background: url("https://cn.oilgasmall.com/uploads/20260115/33bc5a82df554129861b548daa7ce3ca.png");*/ 
    background-repeat: no-repeat;
    background-size: 100% auto;
    background-position: 100% 70%; /* 图片上下显示位置(第二个百分比) */
    border-radius: 5px;
    opacity: 1; /*透明度*/
   /* filter: saturate(0.5);  饱和度 */
    box-shadow: -1px 2px 3px rgba(125, 84, 52, 0.25);
  }
}

/* 📌文案自定义 */
.mes .avatar {
  position: relative;
  bottom: -8px;
  /* === User (右侧气泡) 的文案设置 === */
  &::after {
    /* 修改 User 文案 */
    content: "“我发光，剥落如云母，舒展，让自己如流体般倾泻，于鸟足和树茎叶柄间。”"; 

    /* 样式设置 */
    white-space: pre-wrap;
    font-size: 0.82em;
    color: var(--SmartThemeEmColor);
    line-height: 1.3;

    /* 核心定位 */
    position: absolute;
    top: 40%;
    transform: translateY(-50%); /* 垂直居中 */

    /* 1. 宽度拉框 (一行能放更多字) */
    width: 260px; /* 🔴 觉得不够宽就改大这个数字，比如 300px */

    /* 2. User位置 (在头像左边) */
    right: -15%; /* 放在头像左侧 */
    text-align: left; /* 文字右对齐，贴近头像 */
  }
}

/* === Char (左侧气泡) 的文案设置 === */
.mes[is_user="false"] .avatar {
  position: relative;
  &::after {
    /* 修改 Char 文案 */
